INSERT INTO public.analysis_results (id, lease_id, permissibility_status, summary_text, restrictions_summary, responsibilities_summary, monthly_lease_payment, total_leased_area, lease_area_unit, raw_ai_response, created_at, updated_at, term_length_months, renewal_options, exclusivity_rights, cam_charges, termination_rights, base_rent_psf) VALUES ('03937f8f-0988-4d04-9abe-2a5ecc8e3e77', '4691cf7f-e847-45a2-ab2e-d94de2db0151', 'requires_permission', 'Subleasing requires written consent from the landlord. The landlord has discretionary approval rights.', 'Premises The Premises shall be used only as an impound yard for the storage of vehicles and related equipment and items by the Red Bank Police Departm.... shall not be responsible for the payment of any expenses associated with the Property or the Premises, including, by way of example and without limita.... Against Activities The Premises shall be used only as set forth and provided above, and Lessee shall not use, or permit the use of, the Premises, or a.... Written landlord consent required for any sublease or assignment. Landlord may terminate lease upon tenant default. Lessor''s Remedies in Event of Breach If the Lessee defaults in the performance of any of the terms, covenants and conditions hereof, except for paymen.... Lessor at any time terminate this Lease for any breach, in addition to any other remedy it may have, it may recover from Lessee all damages it may inc.... by Lessee of Lease The voluntary or other surrender of this Lease by Lessee, or a mutual cancellation of the Lease, shall at the option of Lessor, ter.... of Waiver of Breach of Covenants The waiver by Lessor of any breach of any covenant or condition contained in this Lease shall not be deemed to be a w.... subsequent acceptance of rent under this Lease by Lessor shall not be deemed to be a waiver of any preceding breach by Lessee of any covenant or condi.... Lessor''s Remedies on Default It is understood and agreed that the remedies given to Lessor shall be cumulative, and the exercise of any one remedy by .... Effect on Successors and Assigns The covenants and conditions contained in this Lease, subject to the provisions as to assignment, shall apply to and .... Lease supersedes and cancels any and all previous negotiations, arrangements, brochures, agreements and understandings, if any, between the parties he.... modification of this Lease shall be effective unless the same shall be in writing and be signed by the parties hereto or, as the case may be, their re.... of Lease If any clause or provision of this Lease is legally invalid, the remaining clauses and provisions of this Lease shall remain in full force an....', 'shall be responsible for repairing any damaged fencing surrounding the Premises prior to the commencement of this Lease. shall further be responsible for maintaining the fencing surrounding the Premises during the term of this Lease. damage, additions, or changes to the Premises caused by the Lessee are the sole responsibility of the Lessee to repair, restore and/or replace. is in addition to any other remedies the Lessor may have hereunder or by law. Lessee at its cost and expense may install appropriate signage, if any, in or about the Premises, subject to any applicable governmental regulations. termination of this Lease, Lessee shall remove all signage and repair any damage to the Premises related thereto. of Premises All maintenance and repairs, except as described in paragraph 2 herein above, are Lessee''s obligation. by Lessee and Lessee''s Insurance Lessee shall be responsible for and shall relieve, indemnify and save Lessor harmless from and against (a) all liabil....', NULL, NULL, 'sq_ft', '{"clauses": [{"summary": "Premises The Premises shall be used only as an impound yard for the storage of vehicles and related equipment and items by the Red Bank Police Departm...", "risk_flag": "low", "clause_type": "use_restrictions", "original_text": "The Premises\nThe Premises shall be used only as an impound yard for the storage of vehicles and related\nequipment and items by the Red Bank Police Department", "confidence_score": 0.8}, {"summary": "shall be responsible for repairing any damaged fencing surrounding the Premises prior to the commencement of this Lease", "risk_flag": "low", "clause_type": "maintenance", "original_text": "Lessor shall be responsible for repairing\nany damaged fencing surrounding the Premises prior to the commencement of this Lease", "confidence_score": 0.7}, {"summary": "shall further be responsible for maintaining the fencing surrounding the Premises during the term of this Lease", "risk_flag": "medium", "clause_type": "maintenance", "original_text": "Lessor\nshall further be responsible for maintaining the fencing surrounding the Premises during the term\nof this Lease", "confidence_score": 0.7}, {"summary": "damage, additions, or changes to the Premises caused by the Lessee are the sole responsibility of the Lessee to repair, restore and/or replace", "risk_flag": "low", "clause_type": "maintenance", "original_text": "Any damage, additions, or changes to the Premises caused by the\nLessee are the sole responsibility of the Lessee to repair, restore and/or replace", "confidence_score": 0.7}, {"summary": "is in addition to any other remedies the Lessor may have hereunder or by law", "risk_flag": "low", "clause_type": "compliance", "original_text": "This is in addition to any\nother remedies the Lessor may have hereunder or by law", "confidence_score": 0.7}, {"summary": "shall not be responsible for the payment of any expenses associated with the Property or the Premises, including, by way of example and without limita...", "risk_flag": "high", "clause_type": "use_restrictions", "original_text": "Lessee shall not be responsible for the payment of any\nexpenses associated with the Property or the Premises, including, by way of example and without\nlimitation, the cost of utilities, water or sewer usage, security, refuse removal, insurance,\nmaintenance or repair of fixtures, supplies, sundries, sales or use tax on supplies or services, wages\nor salaries of persons engaged in the operation, maintenance and repair of the Property or the\nPremises, expenses incurred for legal and accounting expenses, the cost of capital improvements\nor other modifications to the Property, or any other expense or cost, which, in accordance with\ngenerally accepted accounting principles and the standard management practices for properties\ncomparable to the Property and the Premises would be considered an expense of operating and/or\nmaintaining the Property and/or Premises", "confidence_score": 0.8}, {"summary": "shall not be responsible for the payment of any expenses associated with the Property or the Premises, including, by way of example and without limita...", "risk_flag": "high", "clause_type": "maintenance", "original_text": "Lessee shall not be responsible for the payment of any\nexpenses associated with the Property or the Premises, including, by way of example and without\nlimitation, the cost of utilities, water or sewer usage, security, refuse removal, insurance,\nmaintenance or repair of fixtures, supplies, sundries, sales or use tax on supplies or services, wages\nor salaries of persons engaged in the operation, maintenance and repair of the Property or the\nPremises, expenses incurred for legal and accounting expenses, the cost of capital improvements\nor other modifications to the Property, or any other expense or cost, which, in accordance with\ngenerally accepted accounting principles and the standard management practices for properties\ncomparable to the Property and the Premises would be considered an expense of operating and/or\nmaintaining the Property and/or Premises", "confidence_score": 0.7}, {"summary": "shall not be responsible for the payment of any expenses associated with the Property or the Premises, including, by way of example and without limita...", "risk_flag": "high", "clause_type": "insurance", "original_text": "Lessee shall not be responsible for the payment of any\nexpenses associated with the Property or the Premises, including, by way of example and without\nlimitation, the cost of utilities, water or sewer usage, security, refuse removal, insurance,\nmaintenance or repair of fixtures, supplies, sundries, sales or use tax on supplies or services, wages\nor salaries of persons engaged in the operation, maintenance and repair of the Property or the\nPremises, expenses incurred for legal and accounting expenses, the cost of capital improvements\nor other modifications to the Property, or any other expense or cost, which, in accordance with\ngenerally accepted accounting principles and the standard management practices for properties\ncomparable to the Property and the Premises would be considered an expense of operating and/or\nmaintaining the Property and/or Premises", "confidence_score": 0.8}, {"summary": "Against Activities The Premises shall be used only as set forth and provided above, and Lessee shall not use, or permit the use of, the Premises, or a...", "risk_flag": "high", "clause_type": "use_restrictions", "original_text": "Prohibition Against Activities\nThe Premises shall be used only as set forth and provided above, and Lessee shall not use,\nor permit the use of, the Premises, or any part of the Premises, for any other purpose or purposes,\nwithout the written consent of Lessor", "confidence_score": 0.8}, {"summary": "Lessee at its cost and expense may install appropriate signage, if any, in or about the Premises, subject to any applicable governmental regulations", "risk_flag": "medium", "clause_type": "compliance", "original_text": "Signs\nLessee at its cost and expense may install appropriate signage, if any, in or about the\nPremises, subject to any applicable governmental regulations", "confidence_score": 0.7}, {"summary": "termination of this Lease, Lessee shall remove all signage and repair any damage to the Premises related thereto", "risk_flag": "low", "clause_type": "maintenance", "original_text": "Upon termination of this Lease,\nLessee shall remove all signage and repair any damage to the Premises related thereto", "confidence_score": 0.7}, {"summary": "of Premises All maintenance and repairs, except as described in paragraph 2 herein above, are Lessee''s obligation", "risk_flag": "low", "clause_type": "maintenance", "original_text": "Maintenance of Premises\nAll maintenance and repairs, except as described in paragraph 2 herein above, are Lessee''s\nobligation", "confidence_score": 0.7}, {"summary": "Written landlord consent required for any sublease or assignment", "risk_flag": "medium", "clause_type": "sublease_assignment", "original_text": "Assignments or Sublease\nThe Lessee may not sublease or assign the Premises without Lessor''s prior written consent", "confidence_score": 0.9}, {"summary": "Landlord may terminate lease upon tenant default", "risk_flag": "high", "clause_type": "default_termination", "original_text": "Lessor''s Remedies in Event of Breach\nIf the Lessee defaults in the performance of any of the terms, covenants and conditions\nhereof, except for payment of rent or of any financial obligation under this Lease, or permits the\nPremises to become deserted, abandoned or vacated, the Lessor may give the Lessee notice of such\ndefault, and if Lessee does not cure within ten (10) days, after giving of such notice, or if such\nother default is of such nature that it cannot be completely cured within such period, if the Lessee\ndoes not commence such curing within such ten (10) days and thereafter proceed with reasonable\ndiligence and in good faith to cure such default, then, in any such event the Lessor may terminate\nthis Lease pursuant to applicable law, and on the date specified in said notice, the Lessee''s right\nto possession of the Premises shall cease, and the Lessee shall then quit and surrender the Premises\nto the Lessor", "confidence_score": 0.9}, {"summary": "Lessor''s Remedies in Event of Breach If the Lessee defaults in the performance of any of the terms, covenants and conditions hereof, except for paymen...", "risk_flag": "high", "clause_type": "compliance", "original_text": "Lessor''s Remedies in Event of Breach\nIf the Lessee defaults in the performance of any of the terms, covenants and conditions\nhereof, except for payment of rent or of any financial obligation under this Lease, or permits the\nPremises to become deserted, abandoned or vacated, the Lessor may give the Lessee notice of such\ndefault, and if Lessee does not cure within ten (10) days, after giving of such notice, or if such\nother default is of such nature that it cannot be completely cured within such period, if the Lessee\ndoes not commence such curing within such ten (10) days and thereafter proceed with reasonable\ndiligence and in good faith to cure such default, then, in any such event the Lessor may terminate\nthis Lease pursuant to applicable law, and on the date specified in said notice, the Lessee''s right\nto possession of the Premises shall cease, and the Lessee shall then quit and surrender the Premises\nto the Lessor", "confidence_score": 0.7}, {"summary": "Lessor at any time terminate this Lease for any breach, in addition to any other remedy it may have, it may recover from Lessee all damages it may inc...", "risk_flag": "high", "clause_type": "default_termination", "original_text": "Should Lessor at any time terminate this Lease for any breach, in addition to any\nother remedy it may have, it may recover from Lessee all damages it may incur by reason of such\nbreach", "confidence_score": 0.9}, {"summary": "by Lessee of Lease The voluntary or other surrender of this Lease by Lessee, or a mutual cancellation of the Lease, shall at the option of Lessor, ter...", "risk_flag": "high", "clause_type": "sublease_assignment", "original_text": "Surrender by Lessee of Lease\nThe voluntary or other surrender of this Lease by Lessee, or a mutual cancellation of the\nLease, shall at the option of Lessor, terminate all or any existing subleases or sub tenancies, or\nmay, at the option of Lessor, operate as an assignment of any or all such subleases or sub tenancies\nto the Lessor", "confidence_score": 0.9}, {"summary": "by Lessee of Lease The voluntary or other surrender of this Lease by Lessee, or a mutual cancellation of the Lease, shall at the option of Lessor, ter...", "risk_flag": "high", "clause_type": "default_termination", "original_text": "Surrender by Lessee of Lease\nThe voluntary or other surrender of this Lease by Lessee, or a mutual cancellation of the\nLease, shall at the option of Lessor, terminate all or any existing subleases or sub tenancies, or\nmay, at the option of Lessor, operate as an assignment of any or all such subleases or sub tenancies\nto the Lessor", "confidence_score": 0.9}, {"summary": "of Waiver of Breach of Covenants The waiver by Lessor of any breach of any covenant or condition contained in this Lease shall not be deemed to be a w...", "risk_flag": "high", "clause_type": "default_termination", "original_text": "Effect of Waiver of Breach of Covenants\nThe waiver by Lessor of any breach of any covenant or condition contained in this Lease\nshall not be deemed to be a waiver of such a covenant or condition or any subsequent breach of\nthe covenant or condition or any other covenant or condition", "confidence_score": 0.9}, {"summary": "subsequent acceptance of rent under this Lease by Lessor shall not be deemed to be a waiver of any preceding breach by Lessee of any covenant or condi...", "risk_flag": "high", "clause_type": "default_termination", "original_text": "The subsequent acceptance of rent\nunder this Lease by Lessor shall not be deemed to be a waiver of any preceding breach by Lessee\nof any covenant or condition of this Lease, other than the failure of Lessee to timely pay the\nparticular rent so accepted, regardless of Lessor''s knowledge of such preceding breach at the time\nof acceptance of such rent", "confidence_score": 0.9}, {"summary": "Lessor''s Remedies on Default It is understood and agreed that the remedies given to Lessor shall be cumulative, and the exercise of any one remedy by ...", "risk_flag": "high", "clause_type": "default_termination", "original_text": "Lessor''s Remedies on Default\nIt is understood and agreed that the remedies given to Lessor shall be cumulative, and the\nexercise of any one remedy by Lessor shall not be to the exclusion of any other remedy", "confidence_score": 0.9}, {"summary": "Effect on Successors and Assigns The covenants and conditions contained in this Lease, subject to the provisions as to assignment, shall apply to and ...", "risk_flag": "medium", "clause_type": "sublease_assignment", "original_text": "Binding Effect on Successors and Assigns\nThe covenants and conditions contained in this Lease, subject to the provisions as to\nassignment, shall apply to and bind the heirs, successors, executors, administrators and assigns of\nall of Lessee, and all such heirs, successors, executors, administrators and assignees of Lessee shall\nbe jointly and severally liable under this Lease", "confidence_score": 0.9}, {"summary": "by Lessee and Lessee''s Insurance Lessee shall be responsible for and shall relieve, indemnify and save Lessor harmless from and against (a) all liabil...", "risk_flag": "medium", "clause_type": "insurance", "original_text": "Indemnification by Lessee and Lessee''s Insurance\nLessee shall be responsible for and shall relieve, indemnify and save Lessor harmless from\nand against (a) all liability for loss of life, personal injury and/or damage to property occurring in\nor around the Premises including, but not limited to any claims made by Lessee''s agents, vendors,\nservice providers, guests, invitees, clients, customers, investors or patrons and (b) any loss or\ndamage from Lessee''s failure to perform its obligations under this Lease", "confidence_score": 0.8}, {"summary": "Lease supersedes and cancels any and all previous negotiations, arrangements, brochures, agreements and understandings, if any, between the parties he...", "risk_flag": "low", "clause_type": "use_restrictions", "original_text": "This Lease supersedes and cancels any\nand all previous negotiations, arrangements, brochures, agreements and understandings, if any,\nbetween the parties hereto or displayed by Lessor to Lessee with respect to the subject thereof, and\nnone thereof shall be used to interpret or construe this Lease", "confidence_score": 0.8}, {"summary": "modification of this Lease shall be effective unless the same shall be in writing and be signed by the parties hereto or, as the case may be, their re...", "risk_flag": "low", "clause_type": "sublease_assignment", "original_text": "No modification of this Lease shall be\neffective unless the same shall be in writing and be signed by the parties hereto or, as the case may\nbe, their respective successors or assigns", "confidence_score": 0.9}, {"summary": "of Lease If any clause or provision of this Lease is legally invalid, the remaining clauses and provisions of this Lease shall remain in full force an...", "risk_flag": "low", "clause_type": "use_restrictions", "original_text": "Validity of Lease\nIf any clause or provision of this Lease is legally invalid, the remaining clauses and\nprovisions of this Lease shall remain in full force and effect", "confidence_score": 0.8}], "cam_charges": "Tenant responsible for common area maintenance charges", "summary_text": "Subleasing requires written consent from the landlord. The landlord has discretionary approval rights.", "restrictions_summary": "Premises The Premises shall be used only as an impound yard for the storage of vehicles and related equipment and items by the Red Bank Police Departm.... shall not be responsible for the payment of any expenses associated with the Property or the Premises, including, by way of example and without limita.... Against Activities The Premises shall be used only as set forth and provided above, and Lessee shall not use, or permit the use of, the Premises, or a.... Written landlord consent required for any sublease or assignment. Landlord may terminate lease upon tenant default. Lessor''s Remedies in Event of Breach If the Lessee defaults in the performance of any of the terms, covenants and conditions hereof, except for paymen.... Lessor at any time terminate this Lease for any breach, in addition to any other remedy it may have, it may recover from Lessee all damages it may inc.... by Lessee of Lease The voluntary or other surrender of this Lease by Lessee, or a mutual cancellation of the Lease, shall at the option of Lessor, ter.... of Waiver of Breach of Covenants The waiver by Lessor of any breach of any covenant or condition contained in this Lease shall not be deemed to be a w.... subsequent acceptance of rent under this Lease by Lessor shall not be deemed to be a waiver of any preceding breach by Lessee of any covenant or condi.... Lessor''s Remedies on Default It is understood and agreed that the remedies given to Lessor shall be cumulative, and the exercise of any one remedy by .... Effect on Successors and Assigns The covenants and conditions contained in this Lease, subject to the provisions as to assignment, shall apply to and .... Lease supersedes and cancels any and all previous negotiations, arrangements, brochures, agreements and understandings, if any, between the parties he.... modification of this Lease shall be effective unless the same shall be in writing and be signed by the parties hereto or, as the case may be, their re.... of Lease If any clause or provision of this Lease is legally invalid, the remaining clauses and provisions of this Lease shall remain in full force an....", "permissibility_status": "requires_permission", "responsibilities_summary": "shall be responsible for repairing any damaged fencing surrounding the Premises prior to the commencement of this Lease. shall further be responsible for maintaining the fencing surrounding the Premises during the term of this Lease. damage, additions, or changes to the Premises caused by the Lessee are the sole responsibility of the Lessee to repair, restore and/or replace. is in addition to any other remedies the Lessor may have hereunder or by law. Lessee at its cost and expense may install appropriate signage, if any, in or about the Premises, subject to any applicable governmental regulations. termination of this Lease, Lessee shall remove all signage and repair any damage to the Premises related thereto. of Premises All maintenance and repairs, except as described in paragraph 2 herein above, are Lessee''s obligation. by Lessee and Lessee''s Insurance Lessee shall be responsible for and shall relieve, indemnify and save Lessor harmless from and against (a) all liabil...."}', '2025-08-14 21:44:01.758787+00', '2025-08-14 21:44:01.758787+00', NULL, NULL, NULL, 'Tenant responsible for common area maintenance charges', NULL, NULL);
