Fresh Produce • Handcrafted goods • Live Music • Food Trucks', '2925 W Broad St', 'Columbus', 'OH', '43204', 'US', 39.9546429, -83.0786731, '{https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755565126236-egb49r.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755565126236-ml2v03.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755565126236-m1bb05.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755565126236-armh8b.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755565126236-tlvg3v.png}', 17.5, false, 100, '{}', 'market_stall', 'a67ddd1f-b959-4456-823e-578b923983d4', '2025-08-19 00:58:48.759+00', '2025-08-19 23:59:53.826339+00', 0, 'percentage', 0, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, true);
