INSERT INTO public.properties (id, title, description, address_street, address_city, address_state, address_postal_code, address_country, latitude, longitude, images, price_per_day, inquire_for_pricing, square_feet, amenities, property_type, venue_id, created_at, updated_at, tax_rate, fee_type, fee_value, fee_description, featured, weekly_rate_type, weekly_rate_value, monthly_rate_type, monthly_rate_value, yearly_rate_type, yearly_rate_value, published) VALUES ('71282d67-e3db-4ea2-b831-8abf1faa74c2', 'Pearl Market', 'Downtown’s Only Farmer’s Market For Over Three Decades. Thursdays @ Gay & Pearl Street 11:00AM to 2:00PM

The iconic Gay Street District has been the main hub of the Pearl Market since 1991. We’ve been a fixture in the neighborhood for over three decades, providing farm-fresh produce, artisanal baked goods, gifts for the home and more.

We’re always eager to welcome new vendors to our family of farmers, food producers, artists, and artisans.', '72 E Gay St', 'Columbus', 'OH', '43215', 'US', 39.9639182, -82.9989425, '{https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755562245598-uqg48b.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755562245599-35gpu4.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755562245599-oial2l.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755562245599-15yo0g.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755562245599-lamdu.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755562245599-u6g8ph.png}', NULL, true, 100, '{}', 'market_stall', 'a67ddd1f-b959-4456-823e-578b923983d4', '2025-08-19 00:10:49.118+00', '2025-08-19 23:59:53.826339+00', 0, 'percentage', 0, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, true);
