INSERT INTO public.properties (id, title, description, address_street, address_city, address_state, address_postal_code, address_country, latitude, longitude, images, price_per_day, inquire_for_pricing, square_feet, amenities, property_type, venue_id, created_at, updated_at, tax_rate, fee_type, fee_value, fee_description, featured, weekly_rate_type, weekly_rate_value, monthly_rate_type, monthly_rate_value, yearly_rate_type, yearly_rate_value, published) VALUES ('de165641-9640-4f17-83d9-89e28ecff4ac', 'Powell Street Market and Business Expo', 'Powell Chamber of Commerce presents local vendors market. This is THE event to explore everything our amazing local makers, artists, food vendors, and small businesses have to offer. From handcrafted goods and unique finds to delicious bites and family fun, there’s something for everyone! But that’s not all — our incredible local shops and restaurants will be open and ready to welcome you! Whether you''re in the mood to browse, grab a bite, or unwind on a patio, Downtown Powell has you covered.', '36 Grace Drive', 'Powell', 'OH', '43065', 'US', 40.1633955, -83.0745944, '{https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755564801977-l59bs.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755564801978-itb56.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755564801978-y35428.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755564801978-p5km67.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755564801978-5fmq35.png}', NULL, true, 100, '{}', 'market_stall', 'a67ddd1f-b959-4456-823e-578b923983d4', '2025-08-19 00:53:26.33+00', '2025-08-19 23:59:53.826339+00', 0, 'percentage', 0, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, true);
INSERT INTO public.properties (id, title, description, address_street, address_city, address_state, address_postal_code, address_country, latitude, longitude, images, price_per_day, inquire_for_pricing, square_feet, amenities, property_type, venue_id, created_at, updated_at, tax_rate, fee_type, fee_value, fee_description, featured, weekly_rate_type, weekly_rate_value, monthly_rate_type, monthly_rate_value, yearly_rate_type, yearly_rate_value, published) VALUES ('3b253928-126a-4993-8890-cb130c909250', 'Ohio Expo Center', 'Host to hundreds of popular events and conventions, the Ohio Expo Center is proud to provide one of the most dynamic and unique event venues in the Midwest. As a year-round, multi-purpose convention and meeting facility, the Ohio Expo Center is host to more than 200 events each year, including the annual Ohio State Fair.

Located in the heart of Columbus on a campus occupying 360 acres, 19 buildings and 1.4 million square feet of event space under roof, and on-site parking for 14,000 vehicles, the Ohio Expo Center is one of the most flexible and accommodating sites available. In addition, the Expo Center is easy to reach, located within a half-day drive for half the nation’s population, and just minutes from downtown and Port Columbus International Airport.

If your event requires something special, just let us know. At the Ohio Expo Center, we’re centered around your every need.', '717 E 17th Ave', 'Columbus', 'OH', '43211', 'US', 39.9942444, -82.9929824, '{https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755567482249-82lwf.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755567482250-gtohnj.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755567482250-zt9no7.png,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1755567482250-gwylsl.png}', NULL, true, 75000, '{ac,toilets,electric_outlet,ada_access,loading_dock,security,elevator,heating,parking,water}', 'event_space', 'a67ddd1f-b959-4456-823e-578b923983d4', '2025-08-19 01:38:05.469+00', '2025-08-19 23:59:53.826339+00', 0, 'percentage', 0, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, true);
