INSERT INTO public.properties (id, title, description, address_street, address_city, address_state, address_postal_code, address_country, latitude, longitude, images, price_per_day, inquire_for_pricing, square_feet, amenities, property_type, venue_id, created_at, updated_at, tax_rate, fee_type, fee_value, fee_description, featured, weekly_rate_type, weekly_rate_value, monthly_rate_type, monthly_rate_value, yearly_rate_type, yearly_rate_value, published) VALUES ('48f1817a-5917-4720-a740-f093a57be357', 'The Neighborhood Hive', 'Your community’s heartbeat and hub for connection, creativity, and local flavor.

Our coffee bar brews only the freshest, locally roasted beans, fueling the more than 50 small businesses that make our market a one-of-a-kind experience. But we’re more than just a place to shop and sip.

We’re your go-to space for events, concerts, meditations, parties, and everything in between. Whether you''re hosting an intimate gathering in the Zen Den (perfect for 1–20 guests) or taking over the entire store for a larger celebration, we’ve got the space, the vibe, and the energy to make it memorable.', '2065 E 2100 S', 'Salt Lake City', 'UT', '84109', 'US', 40.7258681, -111.8235983, '{https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1754080372748-ds0b89.jpg,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1754080372749-mya2pq.jpg,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1754080372749-1bcieb.jpg,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1754080372749-yifh14.jpg,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1754080372749-miq874.jpg,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/1754090556256-60y7wo.jpg,https://coandrdclvjebyoadoau.supabase.co/storage/v1/object/public/property-images/properties/fe543d69-f2dc-4097-8b3e-daa379fd3876/48f1817a-5917-4720-a740-f093a57be357/872fc568-a598-461d-989b-952daac17b5d.png}', NULL, true, 50, '{ac,electric_outlet,garden_terrace,internet,loading_dock,storage_stock,counters,heating,kitchen,parking,water,shelves}', 'truck_space', 'fe543d69-f2dc-4097-8b3e-daa379fd3876', '2025-08-01 20:33:03.133+00', '2025-08-20 16:05:12.336096+00', 0, 'percentage', 0, '', false, NULL, NULL, NULL, NULL, NULL, NULL, true);


