INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('43d80808-d98c-4a16-8efe-a2384ce92d08', '73dc938d-0beb-4ab5-b7de-805412ed1fcb', 'What is your cancellation policy?', 'SplitSpace bookings may be canceled by vendor guests until 72 hours before the start date of the booking. Bookings canceled 72 hours before the start date (and cancellations initiated by venue hosts fewer than 72 hours before the start date) will receive a full refund, minus the 3% credit card processing fee. 

Bookings that have already started cannot be canceled unless the venue agrees to the cancellation. If the venue initiates the transaction in that case, the merchant guest will receive a pro-rated refund for the remaining portion of the booking, minus the 3% credit card processing fee. 

As a matter of courtesy, we expect that prior to canceling, the party that needs to cancel would send a message to the other party to explain the reason, and try to reschedule or otherwise rectify the problem.', '{}', 0, true, '''3'':53B,101B ''72'':15B,26B,40B ''a'':48B,87B,107B,125B ''agrees'':69B ''already'':61B ''and'':32B,135B ''as'':106B ''be'':9B,64B ''before'':17B,28B,42B ''booking'':23B,98B ''bookings'':7B,24B,58B ''by'':11B,35B ''cancel'':122B ''canceled'':10B,25B,65B ''canceling'':116B ''cancellation'':4A,72B ''cancellations'':33B ''cannot'':63B ''card'':55B,103B ''case'':81B ''courtesy'':110B ''credit'':54B,102B ''date'':20B,31B,45B ''expect'':112B ''explain'':132B ''fee'':57B,105B ''fewer'':38B ''for'':92B ''full'':49B ''guest'':84B ''guests'':13B ''have'':60B ''hosts'':37B ''hours'':16B,27B,41B ''if'':73B ''in'':79B ''initiated'':34B ''initiates'':76B ''is'':2A ''matter'':108B ''may'':8B ''merchant'':83B ''message'':126B ''minus'':51B,99B ''needs'':120B ''of'':21B,96B,109B ''or'':139B ''other'':129B ''otherwise'':140B ''party'':118B,130B ''policy'':5A ''portion'':95B ''prior'':114B ''pro'':89B ''pro-rated'':88B ''problem'':143B ''processing'':56B,104B ''rated'':90B ''reason'':134B ''receive'':47B,86B ''rectify'':141B ''refund'':50B,91B ''remaining'':94B ''reschedule'':138B ''send'':124B ''splitspace'':6B ''start'':19B,30B,44B ''started'':62B ''than'':39B ''that'':59B,80B,113B,119B ''the'':18B,22B,29B,43B,52B,67B,71B,74B,77B,82B,93B,97B,100B,117B,128B,133B,142B ''to'':70B,115B,121B,127B,131B,137B ''transaction'':78B ''try'':136B ''unless'':66B ''until'':14B ''vendor'':12B ''venue'':36B,68B,75B ''we'':111B ''what'':1A ''will'':46B,85B ''would'':123B ''your'':3A', '2025-08-21 16:42:05.826168+00');
INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('a5e3e849-8f88-43c4-8f07-53858a104561', 'f33ea8b7-8a5f-4938-aa98-174183cafa6e', 'What do you charge fees for?', 'When a prospective merchant finalizes a booking, SplitSpace collects a credit card processing fee of approximately 3%, which is deducted automatically from each payout. We also collect a commission from the venue host. For short-term bookings of one year or less, the fee is 10-15% of the booking value. Long term bookings (more than one year) qualify for a reduced commission of 4-6%. This commission is deducted automatically when the booking is finalized. ', '{costs,fees,commission}', 2, true, '''-15'':54B ''-6'':73B ''10'':53B ''3'':23B ''4'':72B ''a'':8B,12B,16B,34B,68B ''also'':32B ''approximately'':22B ''automatically'':27B,78B ''booking'':13B,57B,81B ''bookings'':44B,61B ''card'':18B ''charge'':4A ''collect'':33B ''collects'':15B ''commission'':35B,70B,75B ''credit'':17B ''deducted'':26B,77B ''do'':2A ''each'':29B ''fee'':20B,51B ''fees'':5A ''finalized'':83B ''finalizes'':11B ''for'':6A,40B,67B ''from'':28B,36B ''host'':39B ''is'':25B,52B,76B,82B ''less'':49B ''long'':59B ''merchant'':10B ''more'':62B ''of'':21B,45B,55B,71B ''one'':46B,64B ''or'':48B ''payout'':30B ''processing'':19B ''prospective'':9B ''qualify'':66B ''reduced'':69B ''short'':42B ''short-term'':41B ''splitspace'':14B ''term'':43B,60B ''than'':63B ''the'':37B,50B,56B,80B ''this'':74B ''value'':58B ''venue'':38B ''we'':31B ''what'':1A ''when'':7B,79B ''which'':24B ''year'':47B,65B ''you'':3A', '2025-08-21 16:39:33.198064+00');
INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('dd738f21-2288-4402-9ccd-5a00f4195f41', 'f33ea8b7-8a5f-4938-aa98-174183cafa6e', 'How much does it cost to list my space?', 'Listings at SplitSpace are free. You may create listings for as many spaces as you like, and there is no fee to create listings or ongoing subscription fees. ', '{costs,fees,pricing,venue}', 1, true, '''and'':26B ''are'':13B ''as'':20B,23B ''at'':11B ''cost'':5A ''create'':17B,32B ''does'':3A ''fee'':30B ''fees'':37B ''for'':19B ''free'':14B ''how'':1A ''is'':28B ''it'':4A ''like'':25B ''list'':7A ''listings'':10B,18B,33B ''many'':21B ''may'':16B ''much'':2A ''my'':8A ''no'':29B ''ongoing'':35B ''or'':34B ''space'':9A ''spaces'':22B ''splitspace'':12B ''subscription'':36B ''there'':27B ''to'':6A,31B ''you'':15B,24B', '2025-08-21 16:32:58.953025+00');
INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('9ebe91d3-910f-4807-a462-54f477c0d6f8', '5ad5f763-14d9-479e-a551-54aa661901d4', 'I opened an inquiry and nobody responded. What can I do?', 'If you don''t receive a response within 48 hours, contact SplitSpace support (<a href="mailto:support@splitspace.com">support@splitspace.com</a>) and we will try to contact the venue host. Venues that don''t respond to inquiries promptly may have their listings removed. ', '{vendor}', 10, true, '''48'':20B ''a'':17B ''an'':3A ''and'':5A,26B ''can'':9A ''contact'':22B,31B ''do'':11A ''don'':14B,37B ''have'':44B ''host'':34B ''hours'':21B ''i'':1A,10A ''if'':12B ''inquiries'':41B ''inquiry'':4A ''listings'':46B ''may'':43B ''nobody'':6A ''opened'':2A ''promptly'':42B ''receive'':16B ''removed'':47B ''respond'':39B ''responded'':7A ''response'':18B ''splitspace'':23B ''support'':24B ''support@splitspace.com'':25B ''t'':15B,38B ''that'':36B ''the'':32B ''their'':45B ''to'':30B,40B ''try'':29B ''venue'':33B ''venues'':35B ''we'':27B ''what'':8A ''will'':28B ''within'':19B ''you'':13B', '2025-08-21 16:42:25.486218+00');
INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('03090e42-d246-4304-baee-161ddc3e979e', 'f24cb008-98fe-4f8a-8393-c3ed0b85e6a3', 'Can I list a space for $0?', 'There are various reasons why you may want to list a space for no fee. You may have a good parking space for a food truck, and want to attract food trucks to your location to feed your employees or customers. You may want to attract certain businesses with free space because of the foot traffic they might attract. You might want to offer free space to nonprofits, such as for the Girl Scouts to sell cookies, while still charging for-profit businesses. You may list your space at $0, or you may list it for a non-zero amount but change the pricing to $0 when you finalize and request payment. In that case, SplitSpace will collect no commission, and we''re happy to be a facilitator anyway. If you are a nonprofit and you would like help finding venues that would be willing to share their space for your fundraising efforts, reach out to us at <a href="mailto:support@splitspace.com">support@splitspace.com</a>.', '{venue}', 5, true, '''0'':7A,98B,115B ''a'':4A,18B,26B,31B,105B,136B,142B ''amount'':109B ''and'':34B,119B,130B,144B ''anyway'':138B ''are'':9B,141B ''as'':77B ''at'':97B,167B ''attract'':37B,53B,66B ''be'':135B,153B ''because'':59B ''businesses'':55B,91B ''but'':110B ''can'':1A ''case'':124B ''certain'':54B ''change'':111B ''charging'':87B ''collect'':127B ''commission'':129B ''cookies'':84B ''customers'':48B ''efforts'':162B ''employees'':46B ''facilitator'':137B ''fee'':22B ''feed'':44B ''finalize'':118B ''finding'':149B ''food'':32B,38B ''foot'':62B ''for'':6A,20B,30B,78B,89B,104B,159B ''for-profit'':88B ''free'':57B,72B ''fundraising'':161B ''girl'':80B ''good'':27B ''happy'':133B ''have'':25B ''help'':148B ''i'':2A ''if'':139B ''in'':122B ''it'':103B ''like'':147B ''list'':3A,17B,94B,102B ''location'':42B ''may'':14B,24B,5