INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('ac818994-7e82-407a-b672-a9ca2e08e58a', '5ad5f763-14d9-479e-a551-54aa661901d4', 'I can''t find any good venues in my area. What can I do?', 'We have talked to many brands that want to expand into physical retail, but don''t know how to go about finding the right space. Many of them come to SplitSpace, and discover that there are no suitable venues in the listings, or there are no venues in their area at all, because we haven''t started serving that region. If you have a particular kind of space in mind, and just don''t know how to approach the owners, or how to arrange the deal, we would be happy to work with you to find and approach the owners of the venues you''d like to target. To reward you for your efforts in attracting new venues to the platform, we can usually arrange for you to get special pricing for your first booking. If you would like to work with us on a project like this, contact SplitSpace support: <a href="mailto:support@splitspace.com">support@splitspace.com</a>.', '{venue}', 8, true, '''a'':78B,159B ''about'':35B ''all'':66B ''and'':46B,85B,111B ''any'':5A ''approach'':92B,112B ''are'':50B,59B ''area'':10A,64B ''arrange'':98B,139B ''at'':65B ''attracting'':130B ''be'':103B ''because'':67B ''booking'':149B ''brands'':20B ''but'':28B ''can'':2A,12A,137B ''come'':43B ''contact'':163B ''d'':119B ''deal'':100B ''discover'':47B ''do'':14A ''don'':29B,87B ''efforts'':128B ''expand'':24B ''find'':4A,110B ''finding'':36B ''first'':148B ''for'':126B,140B,146B ''get'':143B ''go'':34B ''good'':6A ''happy'':104B ''have'':16B,77B ''haven'':69B ''how'':32B,90B,96B ''i'':1A,13A ''if'':75B,150B ''in'':8A,54B,62B,83B,129B ''into'':25B ''just'':86B ''kind'':80B ''know'':31B,89B ''like'':120B,153B,161B ''listings'':56B ''many'':19B,40B ''mind'':84B ''my'':9A ''new'':131B ''no'':51B,60B ''of'':41B,81B,115B ''on'':158B ''or'':57B,95B ''owner