INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('46cbf647-0209-4b18-b23b-5ad0f92fe6a1', 'f24cb008-98fe-4f8a-8393-c3ed0b85e6a3', 'Can I list multiple spaces?', 'You can have an unlimited number of listings. All of your listings will appear in your [Dashboard](/dashboard), where you can manage them.', '{}', 4, true, '''/dashboard'':23B ''all'':14B ''an'':9B ''appear'':19B ''can'':1A,7B,26B ''dashboard'':22B ''have'':8B ''i'':2A ''in'':20B ''list'':3A ''listings'':13B,17B ''manage'':27B ''multiple'':4A ''number'':11B ''of'':12B,15B ''spaces'':5A ''them'':28B ''unlimited'':10B ''where'':24B ''will'':18B ''you'':6B,25B ''your'':16B,21B', '2025-08-21 17:00:16.398506+00');
INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('c09efa78-de40-4d31-8036-cea7d09b7bd6', 'f24cb008-98fe-4f8a-8393-c3ed0b85e6a3', 'What is SplitSpace?', 'SplitSpace is an online marketplace that connects venue hosts with unoccupied or
underutilized commercial spaces with businesses and brands looking to try or expand
their physical retail footprint. Our objective is to help revitalize neighborhoods and
communities by optimizing commercial real estate spaces owned or managed by real
estate property groups while helping small- and mid-sized businesses and digital brands
thrive.', '{}', 1, true, '''an'':6B ''and'':21B,39B,58B,63B ''brands'':22B,65B ''businesses'':20B,62B ''by'':41B,50B ''commercial'':17B,43B ''communities'':40B ''connects'':10B ''digital'':64B ''estate'':45B,52B ''expand'':27B ''footprint'':31B ''groups'':54B ''help'':36B ''helping'':56B ''hosts'':12B ''is'':2A,5B,34B ''looking'':23B ''managed'':49B ''marketplace'':8B ''mid'':60B ''mid-sized'':59B ''neighborhoods'':38B ''objective'':33B ''online'':7B ''optimizing'':42B ''or'':15B,26B,48B ''our'':32B ''owned'':47B ''physical'':29B ''property'':53B ''real'':44B,51B ''retail'':30B ''revitalize'':37B ''sized'':61B ''small'':57B ''spaces'':18B,46B ''splitspace'':3A,4B ''that'':9B ''their'':28B ''thrive'':66B ''to'':24B,35B ''try'':25B ''underutilized'':16B ''unoccupied'':14B ''venue'':11B ''what'':1A ''while'':55B ''with'':13B,19B', '2025-08-21 17:07:44.450874+00');
INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('5d7944e3-6345-4661-b487-1653a90933c4', '73dc938d-0beb-4ab5-b7de-805412ed1fcb', 'Do I need insurance?', 'Both Venue Hosts and Vendor Guests undertaking bookings on the
Platform must have primary liability insurance.

In some jurisdictions, if a Vendor Guest is unable to obtain insurance, they are
legally required to disclose this to the Venue Host at the time of booking and discuss it
with the Venue Host. It will be at the Venue Host’s discretion as to whether they accept
the booking or not under these circumstances. Where a Venue Host accepts a booking
from an uninsured Vendor Guest, the Host indemnifies SplitSpace against all
liabilities, costs, expenses, damages, and losses (including but not limited to any direct,
indirect, or consequential losses, loss of profit, loss of reputation, and all interest,
penalties and legal costs (calculated on a full indemnity basis) and all other reasonable
professional costs and expenses) suffered or incurred by SplitSpace arising out of or in
connection with a Venue Host accepting a booking from an uninsured Vendor Brand
Guest. 

If required by SplitSpace, Vendor Guest and/or Venue Host shall provide
proof of valid event insurance of the type and with the limits as designated by
SplitSpace. If proof of insurance is required, you must provide it to the Venue Host and
SplitSpace prior to the booking or risk the booking being canceled by SplitSpace without
refund to the Vendor Brand Guest.

​Please note that failure to provide evidence of insurance as required may result in the
cancellation of your booking.', '{}', 5, true, '''a'':25B,78B,82B,127B,151B,155B ''accept'':69B ''accepting'':154B ''accepts'':81B ''against'':93B ''all'':94B,119B,132B ''an'':85B,158B ''and'':8B,49B,99B,118B,122B,131B,137B,182B,204B ''and/or'':169B ''any'':106B ''are'':34B ''arising'':144B ''as'':65B,186B,234B ''at'':44B,59B ''basis'':130B ''be'':58B ''being'':214B ''booking'':48B,71B,83B,156B,209B,213B,243B ''bookings'':12B ''both'':5B ''brand'':161B,223B ''but'':102B ''by'':142B,165B,188B,216B ''calculated'':125B ''canceled'':215B ''cancellation'':240B ''circumstances'':76B ''connection'':149B ''consequential'':110B ''costs'':96B,124B,136B ''damages'':98B ''designated'':187B ''direct'':107B ''disclose'':38B ''discretion'':64B ''discuss'':50B ''do'':1A ''event'':177B ''evidence'':231B ''expenses'':97B,138B ''failure'':228B ''from'':84B,157B ''full'':128B ''guest'':27B,88B,162B,168B,224B ''guests'':10B ''have'':17B ''host'':43B,55B,62B,80B,90B,153B,171B,203B ''hosts'':7B ''i'':2A ''if'':24B,163B,190B ''in'':21B,148B,238B ''including'':101B ''incurred'':141B ''indemnifies'':91B ''indemnity'':129B ''indirect'':108B ''insurance'':4A,20B,32B,178B,193B,233B ''interest'':120B ''is'':28B,194B ''it'':51B,56B,199B ''jurisdictions'':23B ''legal'':123B ''legally'':35B ''liabilities'':95B ''liability'':19B ''limited'':104B ''limits'':185B ''loss'':112B,115B ''losses'':100B,111B ''may'':236B ''must'':16B,197B ''need'':3A ''not'':73B,103B ''note'':226B ''obtain'':31B ''of'':47B,113B,116B,146B,175B,179B,192B,232B,241B ''on'':13B,126B ''or'':72B,109B,140B,147B,210B ''other'':133B ''out'':145B ''penalties'':121B ''platform'':15B ''please'':225B ''primary'':18B ''prior'':206B ''professional'':135B ''profit'':114B ''proof'':174B,191B ''provide'':173B,198B,230B ''reasonable'':134B ''refund'':219B ''reputation'':117B ''required'':36B,164B,195B,235B ''result'':237B ''risk'':211B ''s'':63B ''shall'':172B ''some'':22B ''splitspace'':92B,143B,166B,189B,205B,217B ''suffered'':139B ''that'':