INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('fd479c7b-c3bd-4e3f-9a0b-371f5c15f624', 'f24cb008-98fe-4f8a-8393-c3ed0b85e6a3', 'What is the SplitSpace Lease Analyzer?', '[The SplitSpace Lease Analyzer](https://lease.splitspace.com/) is a tool, powered by Artificial Intelligence (AI), to help you with setting up your listing. You will need to upload your lease agreement. Our lease analyzer is not meant to be advice but solely guidance to help find out whether your lease agreement allows you to sublease your space and guide you with suggested competitive pricing for your space based on your existing terms. If your lease agreement does not allow you to sublease, we will provide you with standard amendment for your landlord to sign to allow you to do so. It is your responsibility to consult with a qualified lawyer.', '{}', 10, true, '''/)'':13B ''a'':15B,114B ''advice'':46B ''agreement'':37B,57B,82B ''ai'':21B ''allow'':85B,102B ''allows'':58B ''amendment'':95B ''analyzer'':6A,10B,40B ''and'':64B ''artificial'':19B ''based'':74B ''be'':45B ''but'':47B ''by'':18B ''competitive'':69B ''consult'':112B ''do'':105B ''does'':83B ''existing'':77B ''find'':52B ''for'':71B,96B ''guidance'':49B ''guide'':65B ''help'':23B,51B ''if'':79B ''intelligence'':20B ''is'':2A,14B,41B,108B ''it'':107B ''landlord'':98B ''lawyer'':116B ''lease'':5A,9B,36B,39B,56B,81B ''lease.splitspace.com'':12B ''lease.splitspace.com/)'':11B ''listing'':29B ''meant'':43B ''need'':32B ''not'':42B,84B ''on'':75B ''our'':38B ''out'':53B ''powered'':17B ''pricing'':70B ''provide'':91B ''qualified'':115B ''responsibility'':110B ''setting'':26B ''sign'':100B ''so'':106B ''solely'':48B ''space'':63B,73B ''splitspace'':4A,8B ''standard'':94B ''sublease'':61B,88B ''suggested'':68B ''terms'':78B ''the'':3A,7B ''to'':22B,33B,44B,50B,60B,87B,99B,101B,104B,111B ''tool'':16B ''up'':27B ''upload'':34B ''we'':89B ''what'':1A ''whether'':54B 