INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('9ff4cebc-6c1e-4fbc-bf10-58ee62f437c4', 'f24cb008-98fe-4f8a-8393-c3ed0b85e6a3', 'How do I get started?', 'Create a profile and description for your commercial real estate space, including at least
3 high-resolution photos (ideally 5+ showcasing your space from various angles,
including the best photo of the space as the cover photo). Make it great: The more
details (such as amenities, parking availability, what’s included and what’s not) and the
better the pictures, the more chances of getting noticed and getting bookings. Select
what dates your space is available and whether there is a minimum and/or a maximum
number of days, weeks or months to book your commercial space. Select a daily price
that is competitive, and what discounts you provide for weekly and monthly bookings.', '{}', 2, true, '''3'':20B ''5'':26B ''a'':7B,87B,90B,104B ''amenities'':52B ''and'':9B,58B,62B,73B,83B,110B,117B ''and/or'':89B ''angles'':32B ''as'':40B,51B ''at'':18B ''availability'':54B ''available'':82B ''best'':35B ''better'':64B ''book'':99B ''bookings'':75B,119B ''chances'':69B ''commercial'':13B,101B ''competitive'':109B ''cover'':42B ''create'':6B ''daily'':105B ''dates'':78B ''days'':94B ''description'':10B ''details'':49B ''discounts'':112B ''do'':2A ''estate'':15B ''for'':11B,115B ''from'':30B ''get'':4A ''getting'':71B,74B ''great'':46B ''high'':22B ''high-resolution'':21B ''how'':1A ''i'':3A ''ideally'':25B ''included'':57B ''including'':17B,33B ''is'':81B,86B,108B ''it'':45B ''least'':19B ''make'':44B ''maximum'':91B ''minimum'':88B ''monthly'':118B ''months'':97B ''more'':48B,68B ''not'':61B ''noticed'':72B ''number'':92B ''of'':37B,70B,93B ''or'':96B ''parking'':53B ''photo'':36B,43B ''photos'':24B ''pictures'':66B ''price'':106B ''profile'':8B ''provide'':114B ''real'':14B ''resolution'':23B ''s'':56B,60B ''select'':76B,103B ''showcasing'':27B ''space'':16B,29B,39B,80B,102B ''started'':5A ''such'':50B ''that'':107B ''the'':34B,38B,41B,47B,63B,65B,67B ''there'':85B ''to'':98B ''various'':31B ''weekly'':116B ''weeks'':95B ''what'':55B,59B,77B,111B ''whether'':84B ''you'':113B ''your'':12B,28B,79B,100B', '2025-08-21 18:03:31.239419+00');
INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('9fbcdfbb-8d45-4fb4-a7fb-f69a90e6f68a', '73dc938d-0beb-4ab5-b7de-805412ed1fcb', 'What is and is not allowed in a listing?', 'Don''t include anything in your listing that would violate local laws, including discrimination laws. Do include any restrictions that may be required by your lease, such as limitations on the kind of business allowed, or restrictions on hazardous materials. Do not include your contact
information in your listings. SplitSpace requires all communication between venue hosts and guests to occur within our internal messaging tools, so we can adequately protect both parties in case of any conflicts.', '{}', 10, true, '''a'':8A ''adequately'':78B ''all'':61B ''allowed'':6A,44B ''and'':3A,66B ''any'':27B,85B ''anything'':13B ''as'':37B ''be'':31B ''between'':63B ''both'':80B ''business'':43B ''by'':33B ''can'':77B ''case'':83B ''communication'':62B ''conflicts'':86B ''contact'':54B ''discrimination'':23B ''do'':25B,50B ''don'':10B ''guests'':67B ''hazardous'':48B ''hosts'':65B ''in'':7A,14B,56B,82B ''include'':12B,26B,52B ''including'':22B ''information'':55B ''internal'':72B ''is'':2A,4A ''kind'':41B ''laws'':21B,24B ''lease'':35B ''limitations'':38B ''listing'':9A,16B ''listings'':58B ''local'':20B ''materials'':49B ''may'':30B ''messaging'':73B ''not'':5A,51B ''occur'':69B ''of'':42B,84B ''on'':39B,47B ''or'':45B ''our'':71B ''parties'':81B ''protect'':79B ''required'':32B ''requires'':60B ''restrictions'':28B,46B ''so'':75B ''splitspace'':59B ''such'':36B ''t'':11B ''that'':17B,29B ''the'':40B ''to'':68B ''tools'':74B ''venue'':64B ''violate'':19B ''we'':76B ''what'':1A ''within'':70B ''would'':18B ''your'':15B,34B,53B,57B', '2025-08-21 19:08:27.523355+00');
