INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('724d5882-72cb-492d-b870-d5e8a10ac7dc', '5ad5f763-14d9-479e-a551-54aa661901d4', 'The listings I''m seeing are out of my budget. What can I do?', 'When a venue host responds to an inquiry, they have the ability to modify the pricing. When you open an inquiry, you may make a case for why the opportunity you''re seeking is particularly beneficial, and they may be persuaded to give you special pricing or make some other mutually beneficial arrangement. Often venue hosts will offer discounts based on the length of your
booking, in particular special discounts on weekly and monthly bookings.', '{vendor}', 9, true, '''a'':16B,39B ''ability'':26B ''an'':21B,34B ''and'':51B,87B ''are'':6A ''arrangement'':67B ''based'':74B ''be'':54B ''beneficial'':50B,66B ''booking'':80B ''bookings'':89B ''budget'':10A ''can'':12A ''case'':40B ''discounts'':73B,84B ''do'':14A ''for'':41B ''give'':57B ''have'':24B ''host'':18B ''hosts'':70B ''i'':3A,13A ''in'':81B ''inquiry'':22B,35B ''is'':48B ''length'':77B ''listings'':2A ''m'':4A ''make'':38B,62B ''may'':37B,53B ''modify'':28B ''monthly'':88B ''mutually'':65B ''my'':9A ''of'':8A,78B ''offer'':72B ''often'':68B ''on'':75B,85B ''open'':33B ''opportunity'':44B ''or'':61B ''other'':64B ''out'':7A ''particular'':82B ''particularly'':49B ''persuaded'':55B ''pricing'':30B,60B ''re'':46B ''responds'':19B ''seeing'':5A ''seeking'':47B ''some'':63B ''special'':59B,83B ''the'':1A,25B,29B,43B,76B ''they'':23B,52B ''to'':20B,27B,56B ''venue'':17B,69B ''weekly'':86B ''what'':11A ''when'':15B,31B ''why'':42B ''will'':71B ''you'':32B,36B,45B,58B ''your'':79B', '2025-08-21 16:44:37.518968+00');
INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('ed0c7ee7-1945-4703-9309-9380f3caa107', 'f24cb008-98fe-4f8a-8393-c3ed0b85e6a3', 'How and when will I receive payment for bookings?', 'When you create your account at SplitSpace and register as a venue host, you must connect your Stripe account (or create a new Stripe account if you don''t have one) in order to be able to receive payouts from us. You may publish listings prior to completing your connection to Stripe, but you will not be able to finalize bookings until that process is completed. New Stripe accounts will have a 7 to 14 day onboarding period before they will be able to receive payouts, but will be able to accept payments during that time. Once your Stripe account is active and in good standing, you can specify whether you want daily, weekly, monthly, or manual payouts. If you select daily payouts, you should therefore receive payment for new bookings within one business day of the transaction. ', '{venue}', 15, true, '''14'':84B ''7'':82B ''a'':20B,31B,81B ''able'':45B,67B,92B,99B ''accept'':101B ''account'':14B,28B,34B,109B ''accounts'':78B ''active'':111B ''and'':2A,17B,112B ''as'':19B ''at'':15B ''be'':44B,66B,91B,98B ''before'':88B ''bookings'':9A,70B,140B ''business'':143B ''but'':62B,96B ''can'':117B ''completed'':75B ''completing'':57B ''connect'':25B ''connection'':59B ''create'':12B,30B ''daily'':122B,131B ''day'':85B,144B ''don'':37B ''during'':103B ''finalize'':69B ''for'':8A,138B ''from'':49B ''good'':114B ''have'':39B,80B ''host'':22B ''how'':1A ''i'':5A ''if'':35B,128B ''in'':41B,113B ''is'':74B,110B ''listings'':54B ''manual'':126B ''may'':52B ''monthly'':124B ''must'':24B ''new'':32B,76B,139B ''not'':65B ''of'':145B ''onboarding'':86B ''once'':106B ''one'':40B,142B ''or'':29B,125B ''order'':42B ''payment'':7A,137B ''payments'':102B ''payouts'':48B,95B,127B,132B ''period'':87B ''prior'':55B ''process'':73B ''publish'':53B ''receive'':6A,47B,94B,136B ''register'':18B ''select'':130B ''should'':134B ''specify'':118B ''splitspace'':16B ''standing'':115B ''stripe'':27B,33B,61B,77B,108B ''t'':38B ''that'':72B,104B ''the'':146B ''therefore'':135B ''they'':89B ''time'':105B ''to'':43B,46B,56B,60B,68B,83B,93B,100B ''transaction'':147B ''until'':71B ''us'':50B ''venue'':21B ''want'':121B ''weekly'':123B ''when'':3A,10B ''whether'':119B ''will'':4A,64B,79B,90B,97B ''within'':141B ''you'':11B,23B,36B,51B,63B,116B,120B,129B,133B ''your'':13B,26B,58B,107B', '2025-08-21 16:40:51.080655+00');
INSERT INTO public.faq_entries (id, category_id, question, answer_md, tags, "position", published, search_tsv, created_at) VALUES ('1be52287-feaf-4ef3-8326-9d217ba85941', 'f24cb008-98fe-4f8a-8393-c3ed0b85e6a3', 'What type of listings can I include?', 'We welcome any commercial real estate spaces, which could be for retail, pop-ups,
events, office, meetings, food venues, etc. We welcome creativity—there are many spaces that most people have never considered to be valuable real estate, but nevertheless may be a great venue for another business to use: lobbies, storage rooms, exterior spaces, parking lots, back lots, basements, etc. 

When in doubt, list it at a low price and see if there''s any interest. ', '{}', 3, true, '''a'':51B,76B ''and'':79B ''another'':55B ''any'':10B,84B ''are'':33B ''at'':75B ''back'':66B ''basements'':68B ''be'':17B,43B,50B ''business'':56B ''but'':47B ''can'':5A ''commercial'':11B ''considered'':41B ''could'':16B ''creativity'':31B ''doubt'':72B ''estate'':13B,46B ''etc'':28B,69B ''events'':23B ''exterior'':62B ''food'':26B ''for'':18B,54B ''great'':52B ''have'':39B ''i'':6A ''if'':81B ''in'':71B ''include'':7A ''interest'':85B ''it'':74B ''list'':73B ''listings'':4A ''lobbies'':59B ''lots'':65B,67B ''low'':77B ''many'':34B ''may'':49B ''meetings'':25B ''most'':37B ''never'':40B ''nevertheless'':48B ''of'':3A ''office'':24B ''parking'':64B ''people'':38B ''pop'':21B ''pop-ups'':20B ''price'':78B ''real'':12B,45B ''retail'':19B ''rooms'':61B ''s'':83B ''see'':80B ''spaces'':14B,35B,63B ''storage'':60B ''that'':36B ''there'':32B,82B ''to'':42B,57B ''type'':2A ''ups'':22B ''use'':58B ''valuable'':44B ''venue'':53B ''venues'':27B ''we'':8B,29B ''welcome'':9B,30B ''what'':1A ''when'':70B ''which'':15B', '2025-08-21 18:02:01.058222+00');


