INSERT INTO public.lease_clauses (id, lease_id, clause_type, summary, risk_flag, original_text, page_number, confidence_score, created_at) VALUES ('dc0a4e4f-8e13-4869-8974-4b55fa837271', '4691cf7f-e847-45a2-ab2e-d94de2db0151', 'use_restrictions', 'shall not be responsible for the payment of any expenses associated with the Property or the Premises, including, by way of example and without limita...', 'high', 'Lessee shall not be responsible for the payment of any
expenses associated with the Property or the Premises, including, by way of example and without
limitation, the cost of utilities, water or sewer usage, security, refuse removal, insurance,
maintenance or repair of fixtures, supplies, sundries, sales or use tax on supplies or services, wages
or salaries of persons engaged in the operation, maintenance and repair of the Property or the
