INSERT INTO public.reviews (id, property_id, reviewer_id, rating, content, verified_booking, review_eligibility, status, created_at, updated_at) VALUES ('95e30a4c-7f58-4603-b460-12ad4ba66729', '9bcc764f-ee21-46c5-979a-144f04af929e', '11941eee-4b5a-49ea-aaae-b7c66f7a5462', 4, 'I''d never played pickleball, but everyone was awesome and helpful. ', false, '{"booking_id": null, "inquiry_id": null, "payment_status": "none", "completed_booking": false}', 'approved', '2025-06-04 03:17:56.110081+00', '2025-06-04 03:17:56.110081+00');
